// ==========================================
const permissionsList = {
  "check:user_id_provided": null,       // пользователь запрошен
  "check:user_is_lead": null,           // пользователь является лидом
  "check:user_is_admin": null,          // пользователь является админом
  "check:user_is_active": null,         // пользователь разблокирован

  "check:channel_id_provided": null,    // канал запрошен
  "check:channel_found": null,          // канал зарегистрирован
  "check:channel_is_active": null,      // канал разблокирован
  "check:bot_is_member": null,          // бот находится в канале
  "check:user_is_channel_admin": null,  // пользователь является админом канала
  "check:user_is_subscribed": null,     // пользователь подписан
  "check:channel_name": null            // название канала
};

// ==========================================
// ПРОСТАЯ КОНВЕРТАЦИЯ ДЛЯ НОДЫ REDIS
// ==========================================
return Object.keys(permissionsList).map(key => {
  return {
    json: {
      redis_key: key,
      redis_value: permissionsList[key] === null ? "null" : String(permissionsList[key])
    }
  };
});

