parameters.query:
SELECT EXISTS (
    SELECT 1 
    FROM "atgate"."AtGateUser" 
    WHERE user_id = {{ $('Вход').item.json.user }}
) AS user_found;
;

SELECT EXISTS (
    SELECT 1 
    FROM "atgate"."AtGateAdmins" 
    WHERE user_id = {{ $('Вход').item.json.user }}
) AS is_admin;
;

SELECT EXISTS (
    SELECT 1 
    FROM "atgate"."AtGateAdmins" 
    WHERE user_id = {{ $('Вход').item.json.user }} 
      AND is_blocked = false
) AS is_active;

SELECT EXISTS (
    SELECT 1 
    FROM "atgate"."AtGateChannel" 
    WHERE channel_id = {{ $('Вход').item.json.channel }}
) AS is_exist;

SELECT EXISTS (
    SELECT 1 
    FROM "atgate"."AtGateChannel" 
    WHERE channel_id = {{ $('Вход').item.json.channel }} 
      AND is_blocked = false
) AS is_active;

